--PostgreSQL database dump bibliotecaSET statement_timeout = 0;SET lock_timeout = 0;SET client_encoding = 'UTF8';-- drop tablesDROP TABLE IF EXISTS reserva CASCADE;DROP TABLE IF EXISTS emprestimo CASCADE;DROP TABLE IF EXISTS exemplar CASCADE;DROP TABLE IF EXISTS obra CASCADE;DROP TABLE IF EXISTS usuario CASCADE;DROP TABLE IF EXISTS bibliotecario CASCADE;-- tabela usuarioCREATE TABLE usuario (    id_usuario SERIAL PRIMARY KEY,    nome VARCHAR(100) NOT NULL,    email VARCHAR(100) UNIQUE NOT NULL,    senha VARCHAR(100) NOT NULL,    status VARCHAR(20) DEFAULT 'ativo');-- tabela bibliotecarioCREATE TABLE bibliotecario (    id_bibliotecario SERIAL PRIMARY KEY,    nome VARCHAR(100) NOT NULL,    email VARCHAR(100) UNIQUE NOT NULL);-- tabela obraCREATE TABLE obra (    id_obra SERIAL PRIMARY KEY,    titulo VARCHAR(200) NOT NULL,    genero VARCHAR(50),    tipo VARCHAR(50),	autor VARCHAR(50));-- tabela exemplarCREATE TABLE exemplar (    id_exemplar SERIAL PRIMARY KEY,    id_obra INTEGER NOT NULL,    status VARCHAR(20) DEFAULT 'disponivel',    CONSTRAINT fk_obra        FOREIGN KEY (id_obra)        REFERENCES obra(id_obra)        ON DELETE CASCADE);-- tabela emprestimoCREATE TABLE emprestimo (    id_emprestimo SERIAL PRIMARY KEY,    id_usuario INTEGER NOT NULL,    id_exemplar INTEGER NOT NULL,    data_emprestimo DATE NOT NULL,    data_prevista_devolucao DATE NOT NULL,    data_devolucao DATE,    status VARCHAR(20) DEFAULT 'ativo',    CONSTRAINT fk_usuario        FOREIGN KEY (id_usuario)        REFERENCES usuario(id_usuario)        ON DELETE CASCADE,    CONSTRAINT fk_exemplar        FOREIGN KEY (id_exemplar)        REFERENCES exemplar(id_exemplar)        ON DELETE CASCADE);-- tabela reservaCREATE TABLE reserva (    id_reserva SERIAL PRIMARY KEY,    id_usuario INTEGER NOT NULL,    id_obra INTEGER NOT NULL,    data_reserva DATE NOT NULL DEFAULT CURRENT_DATE,    status VARCHAR(20) DEFAULT 'ativa',    CONSTRAINT fk_reserva_usuario        FOREIGN KEY (id_usuario)        REFERENCES usuario(id_usuario)        ON DELETE CASCADE,    CONSTRAINT fk_reserva_obra        FOREIGN KEY (id_obra)        REFERENCES obra(id_obra)        ON DELETE CASCADE,    CONSTRAINT chk_status_reserva        CHECK (status IN ('ativa', 'cancelada', 'atendida')));INSERT INTO usuario (nome, email, senha, status) VALUES('Bruno', 'Bruno@email.com', 'bruno02', 'ativo'),('Marcos', 'mariana@email.com', 'marcos03', 'suspenso');INSERT INTO bibliotecario (nome, email) VALUES('Ana Carolina', 'anacarolina@ufmg.com'),('Paulo', 'paulo@ufmg.com');INSERT INTO obra (titulo, genero, tipo, autor) VALUES('Dom Casmurro', 'Romance', 'Livro', 'Machado de Assis'),('O Pequeno Príncipe', 'Fantasia', 'Livro', 'Jean Saint-Exupeerry'),('Cálculo I', 'Acadęmico', 'Livro', 'James Stewart');INSERT INTO exemplar (id_obra, status) VALUES(1, 'disponivel'),(1, 'emprestado'),(2, 'disponivel'),(3, 'disponivel'),(3, 'disponivel');INSERT INTO emprestimo (    id_usuario,    id_exemplar,    data_emprestimo,    data_prevista_devolucao,    data_devolucao,    status) VALUES(1, 2, '2026-04-01', '2026-04-10', NULL, 'ativo'),(2, 1, '2026-03-20', '2026-03-30', '2026-03-29', 'devolvido');INSERT INTO emprestimo (id_usuario,id_exemplar,data_emprestimo,data_prevista_devolucao,data_devolucao,status) VALUES(1, 2, '2026-04-01', '2026-04-10', NULL, 'ativo'),(2, 1, '2026-03-20', '2026-03-30', '2026-03-29', 'devolvido');INSERT INTO reserva (id_usuario, id_obra, data_reserva, status) VALUES(1, 2, '2026-04-10', 'ativa'),(2, 1, '2026-04-09', 'atendida');